import{_ as t,o,c as r,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const h=JSON.parse('{"title":"Charte Graphique & Ton","description":"","frontmatter":{"title":"Charte Graphique & Ton"},"headers":[],"relativePath":"docs/fr/resources/brand-tone.md","filePath":"docs/fr/resources/brand-tone.md"}'),s={name:"docs/fr/resources/brand-tone.md"};function i(n,e,u,d,l,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="charte-graphique-ton-de-communication" tabindex="-1">Charte Graphique &amp; Ton de Communication <a class="header-anchor" href="#charte-graphique-ton-de-communication" aria-label="Permalink to &quot;Charte Graphique &amp; Ton de Communication&quot;">​</a></h1><p class="gi-page-intro">Comment écrire et parler comme getinside — pour une communication cohérente, professionnelle et efficace.</p><h2 id="la-regle-d-or-le-nom-de-la-marque" tabindex="-1">La règle d&#39;or : le nom de la marque <a class="header-anchor" href="#la-regle-d-or-le-nom-de-la-marque" aria-label="Permalink to &quot;La règle d&#39;or : le nom de la marque&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Une seule règle orthographique, sans exception</p><p>Le nom s&#39;écrit <strong>toujours en minuscules : getinside</strong></p><p>Jamais &quot;Getinside&quot;, jamais &quot;GetInside&quot;, jamais &quot;GETINSIDE&quot; — même en début de phrase, même dans un titre.</p></div><h2 id="le-positionnement-editorial" tabindex="-1">Le positionnement éditorial <a class="header-anchor" href="#le-positionnement-editorial" aria-label="Permalink to &quot;Le positionnement éditorial&quot;">​</a></h2><p>getinside est un <strong>Facilitateur Technologique</strong> — une solution SaaS de Retail Media. Pas une agence créa, pas un réseau publicitaire traditionnel.</p><p><strong>Ce que ça change dans la communication :</strong></p><ul><li>On vend de la <strong>Performance</strong> et du <strong>Chiffre d&#39;Affaires</strong>, pas du &quot;branding flou&quot;</li><li>On parle de <strong>ROI mesurable</strong>, pas d&#39;exposition ou de notoriété vague</li><li>On est un <strong>partenaire technologique</strong>, pas un prestataire de service</li></ul><p><strong>Mantra :</strong> <em>&quot;Transformez les audiences en chiffre d&#39;affaires.&quot;</em></p><h2 id="ton-de-communication" tabindex="-1">Ton de communication <a class="header-anchor" href="#ton-de-communication" aria-label="Permalink to &quot;Ton de communication&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Professionnel</strong><p>Sérieux et crédible. Pas de familiarités excessives, pas de tutoyage non sollicité.</p></div><div class="gi-value-card"><strong>Énergique</strong><p>Dynamique, enthousiaste. On croit en ce qu&#39;on fait. Pas de passif, pas de conditionnel frileux.</p></div><div class="gi-value-card"><strong>Direct</strong><p>Phrases courtes. Verbes d&#39;action. On va à l&#39;essentiel sans détours ni périphrase.</p></div><div class="gi-value-card"><strong>Rassurant</strong><p>On dépersonnalise les problèmes (&quot;c&#39;est une norme industrielle&quot;) et on guide vers la solution.</p></div></div><h2 id="vocabulaire-officiel" tabindex="-1">Vocabulaire officiel <a class="header-anchor" href="#vocabulaire-officiel" aria-label="Permalink to &quot;Vocabulaire officiel&quot;">​</a></h2><h3 id="utilisez-ces-termes" tabindex="-1">Utilisez ces termes <a class="header-anchor" href="#utilisez-ces-termes" aria-label="Permalink to &quot;Utilisez ces termes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Domaine</th><th>Termes à utiliser</th></tr></thead><tbody><tr><td><strong>Format</strong></td><td>Insertion colis · Insertion panier · Social publishing · Emailing dédié</td></tr><tr><td><strong>Concepts</strong></td><td>Retail Media · Monétisation · Audience · Inventaire · Levier d&#39;acquisition</td></tr><tr><td><strong>Technologie</strong></td><td>Solution SaaS · Reporting intégré · Extension d&#39;audience</td></tr><tr><td><strong>Bénéfices</strong></td><td>Revenus additionnels · Ciblage comportemental · Performance · Mesurable · Rentable</td></tr></tbody></table><h3 id="evitez-ces-termes" tabindex="-1">Évitez ces termes <a class="header-anchor" href="#evitez-ces-termes" aria-label="Permalink to &quot;Évitez ces termes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Terme à éviter</th><th>Utiliser à la place</th></tr></thead><tbody><tr><td>&quot;Asile colis&quot;</td><td><strong>&quot;Insertion colis&quot;</strong> (sauf contexte explicatif)</td></tr><tr><td>&quot;Agence&quot;, &quot;Prestataire&quot;</td><td>&quot;Facilitateur technologique&quot;, &quot;Partenaire&quot;</td></tr><tr><td>Jargon technique non expliqué</td><td>Termes simples + parenthèse explicative</td></tr><tr><td>Voix passive</td><td>Verbes d&#39;action actifs</td></tr><tr><td>Phrases longues</td><td>Max 1-2 lignes par idée</td></tr></tbody></table><h2 id="formules-do-s-don-ts" tabindex="-1">Formules DO&#39;s / DON&#39;Ts <a class="header-anchor" href="#formules-do-s-don-ts" aria-label="Permalink to &quot;Formules DO&#39;s / DON&#39;Ts&quot;">​</a></h2><h3 id="pour-les-distributeurs-—-focus-revenu-sans-effort" tabindex="-1">Pour les Distributeurs — Focus &quot;Revenu sans effort&quot; <a class="header-anchor" href="#pour-les-distributeurs-—-focus-revenu-sans-effort" aria-label="Permalink to &quot;Pour les Distributeurs — Focus &quot;Revenu sans effort&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th>❌ DON&#39;T</th><th>✅ DO</th></tr></thead><tbody><tr><td>&quot;Nous avons une fonctionnalité qui permet de générer des revenus&quot;</td><td><strong>&quot;Rentabilisez votre audience. Déléguez la vente de votre inventaire.&quot;</strong></td></tr><tr><td>&quot;Il est possible de monétiser vos colis&quot;</td><td><strong>&quot;Monétisez chaque colis expédié.&quot;</strong></td></tr><tr><td>&quot;Vous pourriez recevoir des campagnes&quot;</td><td><strong>&quot;Activez. Recevez des campagnes. Encaissez.&quot;</strong></td></tr></tbody></table><h3 id="pour-les-annonceurs-—-focus-ciblage-roi" tabindex="-1">Pour les Annonceurs — Focus &quot;Ciblage &amp; ROI&quot; <a class="header-anchor" href="#pour-les-annonceurs-—-focus-ciblage-roi" aria-label="Permalink to &quot;Pour les Annonceurs — Focus &quot;Ciblage &amp; ROI&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th>❌ DON&#39;T</th><th>✅ DO</th></tr></thead><tbody><tr><td>&quot;Nous proposons de la publicité chez des e-commerçants&quot;</td><td><strong>&quot;Touchez votre cible par comportement d&#39;achat.&quot;</strong></td></tr><tr><td>&quot;Vous pouvez diffuser vos messages via notre réseau&quot;</td><td><strong>&quot;Diversifiez vos canaux d&#39;acquisition. Mesurez chaque euro investi.&quot;</strong></td></tr><tr><td>&quot;Notre solution est disponible pour les marques&quot;</td><td><strong>&quot;Démarrez dès aujourd&#39;hui. Accessible à tous les budgets.&quot;</strong></td></tr></tbody></table><h3 id="verbes-d-action-a-privilegier" tabindex="-1">Verbes d&#39;action à privilégier <a class="header-anchor" href="#verbes-d-action-a-privilegier" aria-label="Permalink to &quot;Verbes d&#39;action à privilégier&quot;">​</a></h3><p><code>Monétisez</code> · <code>Activez</code> · <code>Touchez</code> · <code>Mesurez</code> · <code>Encaissez</code> · <code>Rentabilisez</code> · <code>Déléguez</code> · <code>Générez</code> · <code>Démarrez</code> · <code>Boostez</code></p><h2 id="formules-de-resolution-de-situations-delicates" tabindex="-1">Formules de résolution de situations délicates <a class="header-anchor" href="#formules-de-resolution-de-situations-delicates" aria-label="Permalink to &quot;Formules de résolution de situations délicates&quot;">​</a></h2><p>Ces formules permettent de dépersonnaliser les conflits et de répondre avec autorité sans créer de friction.</p><h3 id="face-a-un-surplus-d-impression-gache" tabindex="-1">Face à un surplus d&#39;impression (gâche) <a class="header-anchor" href="#face-a-un-surplus-d-impression-gache" aria-label="Permalink to &quot;Face à un surplus d&#39;impression (gâche)&quot;">​</a></h3><p>Ne parlez jamais d&#39;&quot;erreur&quot;. C&#39;est une norme industrielle.</p><blockquote><p><em>&quot;Ce volume excédentaire n&#39;est pas une erreur de commande, mais une tolérance technique (gâche) inhérente à l&#39;impression industrielle. Elle est régie par l&#39;Article 38 du Code des usages de l&#39;industrie graphique qui stipule que &#39;l&#39;acheteur est tenu d&#39;accepter&#39; ces variations...&quot;</em></p></blockquote><h3 id="face-a-une-demande-de-transfert-de-donnees-client" tabindex="-1">Face à une demande de transfert de données client <a class="header-anchor" href="#face-a-une-demande-de-transfert-de-donnees-client" aria-label="Permalink to &quot;Face à une demande de transfert de données client&quot;">​</a></h3><blockquote><p><em>&quot;En Retail Media, la donnée est un actif First Party qui appartient exclusivement au Distributeur. Le transfert de fichier est juridiquement interdit sans un nouvel Opt-in spécifique (RGPD). getinside protège cet actif pour vous.&quot;</em></p></blockquote><h3 id="face-a-un-refus-subjectif-sur-un-visuel-conforme" tabindex="-1">Face à un refus subjectif sur un visuel conforme <a class="header-anchor" href="#face-a-un-refus-subjectif-sur-un-visuel-conforme" aria-label="Permalink to &quot;Face à un refus subjectif sur un visuel conforme&quot;">​</a></h3><p>Ramenez le débat sur la technique :</p><blockquote><p><em>&quot;Le Distributeur dispose d&#39;un droit de veto sur les marques incompatibles avec son positionnement. En revanche, si le visuel respecte les critères techniques (zone tranquille, 300 DPI, mentions légales conformes), le refus doit être motivé par un critère objectif — pas par une préférence stylistique.&quot;</em></p></blockquote><hr><p><strong>Voir aussi :</strong> <a href="/handbook/docs/fr/resources/studio.html">Studio Créatif</a> · <a href="/handbook/docs/fr/advertisers/sponsored-mail/design-guide/legal.html">Mentions Légales Insertion Colis</a></p>',35)])])}const p=t(s,[["render",i]]);export{h as __pageData,p as default};
